// Parse Ollama JSON response. On failure, fall back to raw text split into lines.
const prevItem = $('Code - Trim Transcript').first().json;
const rawResponse = items[0].json.message && items[0].json.message.content
  ? items[0].json.message.content
  : '';

let main_idea, summary;
try {
  const parsed = JSON.parse(rawResponse);
  main_idea = parsed.main_idea || '';
  summary = Array.isArray(parsed.summary) ? parsed.summary : [];
} catch (e) {
  // Fallback: first sentence as main_idea, first 10 lines as summary
  const lines = rawResponse.split('\n').map(l => l.trim()).filter(Boolean);
  summary = lines.slice(0, 10);
  main_idea = lines[0] ? lines[0].split('.')[0] + '.' : 'Не удалось распарсить ответ.';
}

return [{
  json: {
    videoId: prevItem.videoId,
    title: prevItem.title,
    url: prevItem.url,
    lang: prevItem.lang,
    main_idea: main_idea,
    summary: summary
  }
}];

// HTML-escape title, main_idea, and each summary bullet, then compose Telegram message.
function escapeHtml(str) {
  if (typeof str !== 'string') str = String(str || '');
  return str.replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;');
}

const { videoId, title, url, main_idea, summary } = items[0].json;

const escapedTitle = escapeHtml(title);
const escapedMainIdea = escapeHtml(main_idea);
const bulletLines = Array.isArray(summary)
  ? summary.map(s => `• ${escapeHtml(s)}`).join('\n')
  : '';

const text = `<b>${escapedTitle}</b>\n<a href="https://youtu.be/${videoId}">Смотреть на YouTube</a>\n\n📌 <b>Главная идея</b>\n${escapedMainIdea}\n\n📝 <b>Обзор</b>\n${bulletLines}`;

return [{
  json: {
    videoId: videoId,
    title: title,
    url: url,
    lang: items[0].json.lang,
    text: text
  }
}];

// Mark video as processed with status 'summarized' in SQLite.
const Database = require('better-sqlite3');
const db = new Database('/home/node/.n8n/state.db');
const stmt = db.prepare(`INSERT OR REPLACE INTO processed_videos
  (video_id, title, status, lang) VALUES (?, ?, ?, ?)`);
for (const item of items) {
  stmt.run(item.json.videoId, item.json.title, 'summarized', item.json.lang || null);
}
return items;

// Carry forward videoId, title, url, lang from the loop item for the 'no transcript' path.
const loopItem = $('Loop Over Items').first().json;
return [{
  json: {
    videoId: loopItem.videoId,
    title: loopItem.title,
    url: loopItem.url,
    lang: null
  }
}];

// Mark video as processed with status 'no_transcript' in SQLite.
const Database = require('better-sqlite3');
const db = new Database('/home/node/.n8n/state.db');
const stmt = db.prepare(`INSERT OR REPLACE INTO processed_videos
  (video_id, title, status, lang) VALUES (?, ?, ?, ?)`);
for (const item of items) {
  stmt.run(item.json.videoId, item.json.title, 'no_transcript', null);
}
return items;
